import Foundation

func solve(prices: Array<Int64>, strategy: Array<Int64>, k: Int64) -> Int64 {
    let n = prices.count
    var maxProfit = 0

    // Calculate the original profit
    var profit = 0
    for i in 0..<n {
        profit += Int64(strategy[i]) * prices[i]
    }
    maxProfit = profit

    // Try to modify each possible consecutive k elements
    for i in 0..<n - k + 1 {
        // Calculate the profit change if we modify the subarray from i to i + k - 1
        var change = 0
        // Original strategy in the subarray: first k/2 elements are -1, next k/2 are 1
        for j in 0..<k {
            if j < k/2 {
                // Original was -1, now it's 0 (hold)
                change += Int64(strategy[i + j]) * prices[i + j]
            } else {
                // Original was 1, now it's 1 (sell)
                change += Int64(strategy[i + j]) * prices[i + j]
            }
        }
        // New strategy in the subarray: first k/2 elements are 0 (hold), next k/2 are 1 (sell)
        for j in 0..<k {
            if j < k/2 {
                // New is 0, original was strategy[i + j]
                change -= Int64(strategy[i + j]) * prices[i + j]
            } else {
                // New is 1, original was strategy[i + j]
                change += Int64(strategy[i + j]) * prices[i + j]
            }
        }
        // Update maxProfit
        maxProfit = max(maxProfit, profit + change)
    }

    return Int64(maxProfit)
}
